%[text] # 흑백 이미지
"양연우" %[output:32bc58ec]
%%
%[text] ## 간단한 흑백 이미지
%[text] - zeros \
clear;
h = 100; % 높이
w = 200; % 폭
v = 100; % 밝기
G = zeros(h, w, 'uint8') + v;
imshow(G) %[output:1ed2d4f6]
%%
%[text] - ones \
clear;
h = 100; % 높이
w = 200; % 폭
v = 200; % 밝기
G = ones(h, w, 'uint8') * v;
imshow(G) %[output:2cfc4d48]
%%
%[text] ## 연습 문제 1: 밝기 값이 128인 200 x 300 흑백 이미지 M을 만들고 보여주세요
clear;
h = 200; % 높이
w = 300; % 폭
v = 128;
M = zeros(h, w, 'uint8') + v;
% M = zeros(h, w, 'uint8') * v;
imshow(M) %[output:300011cc]
%%
%[text] ## 반반 이미지
%[text] - ones \
clear;
h = 100; % 높이
w = 200; % 폭
v = [50 150]; % 밝기 [50 150]
G = ones(h, w, 'uint8') * v(1); % 전체 사각형 밝기 50
G(:, 101: 200) = v(2); % 101 부터 200까지 밝기 150
imshow(G) %[output:1b9ea366]
%%
%[text] - zeros \
clear;
h = 100; % 높이
w = 200; % 폭
v = [50 150]; % 밝기 [50 150]
G = zeros(h, w, 'uint8') + v(1); % 전체 사각형 밝기 50
G(:, 101: 200) = v(2); % 101 부터 200까지 밝기 150
imshow(G) %[output:4e3709a7]
%%
%[text] ## 반반 이미지 -kron()
%[text] - kron(A, B) 함수는 A와 B의 텐서곱을 계산 \
clear;
h = 100; % 높이
w = 100; % 폭
v = uint8([50 150]); % 밝기 1x2
B = ones(h, w, 'uint8'); % 100x100
G = kron(v, B); % 1x2를 한 묶음으로 묶어 100x100 -> 100x200 폭의 절반은 50, 절반은 150
imshow(G) %[output:7fd89116]
h1 = 100; % 높이
w1 = 100; % 폭
v1 = uint8([50 150]); % 밝기 1x2
B1 = zeros(h1, w1, 'uint8'); % 100x100
G1 = kron(v1, B1); % 1x2를 한 묶음으로 묶어 100x100 -> 100x200 그러나 곱했을 때 0*50 이기에 0...
imshow(G1) %[output:428fdf1b]
%%
%[text] ## 흑백 그라데이션 띠 만들기
clear;
h = 100; % 높이
w = 20; % 폭
v = uint8(240: -10: 40); % 밝기가 240부터 -10씩 40까지
B = ones(h, w, 'uint8'); % 100x20 사이즈 사각형
G = kron(v, B); % 1x21(계단식 밝기 정보) 100x20 -> 100x420
imshow(G) %[output:635f50eb]
%%
%[text] ## 연습 문제 2: 흑백 팔레트 만들기
%[text] - 밝기가 10 ~ 240이며 각각 50x50인 흑백 팔레트를 만드시오 \
clear;
h = 50;
w = 50;

v = uint8(10: 40: 240); % 1x6 uint8 (밝기 정보)
v2 = v +10;
v3 = v2 +10;
v4 = v3 +10;

B = ones(h, w, 'uint8'); % 50x50

G = kron(v, B); % 50x300
G1 = kron(v2, B);
G2 = kron(v3, B);
G3 = kron(v4, B);

Result = [G; G1; G2; G3];
imshow(Result) %[output:7e10309c]
%%
%[text] ## 랜덤 흑백 타일 만들기
%[text] - randi(imax, m, n): 1 ~ imax 사이에 랜덤 정수로 이루어진 mxn 행렬 \
clear;
h = 20; % 높이
w = 20; % 폭

B = ones(h, w, 'uint8'); % 20x20

r = randi(255, 10, 10, 'uint8'); % 10x10 크기로 밝기는 1~255 사이의 정수

G = kron(r, B); % 200x200에 밝기 정보
imshow(G) %[output:604b7413]
%[text] ## 테두리 만들기
%[text] - padarray(): 함수로 테두리를 만들 수 있다
%[text] -  /  **배열의 바깥쪽에 값을 덧붙여서 크기를 키우는 함수** \
bd = [10, 10];
D = padarray(G, bd, 0, "both"); 
% G에 상하 10(bd), 좌우(both) 10(bd)만큼 바깥에 검은색으로 추가
% "both"가 상하좌우 모두 적용되개 해줌
imshow(D) %[output:60a06b29]
%%
%[text] ## 연습문제 3: 2중 테두리 만들기
clear;
h = 50;
w = 50;

C = ones(h, w, 'uint8'); %50 x 50

v = uint8(linspace(10, 240, 25)); %1x25
v2 = reshape(v, 5, 5)';

G = kron(v2, C);

bd = [10 10];
W = padarray(G, bd, 255, 'both');
B = padarray(W, bd, 0, 'both');
imshow(B) %[output:46b556fd]
%%
%[text] ## 부등식을 이용한 흑백 이미지
%[text] - meshgrid()를 이용하여 부등식으로 흑백 이미지 만들기
%[text] - $y = x + 100$의 그래프 \
clear;
x = -200 : 200; % -200~200 벡터
y = x + 100; % 기울기 1, y절편 100인 직선이야
plot(x, y, 'LineWidth', 1); %[output:1828cff7]
% 가로축: x 세로축: y / 선 두께를 1로 지정
axis equal; % x축 1단위와 y축 1단위의 길이를 같게 맞춤 %[output:1828cff7]
axis square; % 그래프가 그려지는 축 영역 자체를 정사각형으로 만듦 %[output:1828cff7]
grid on; % 격자선 표시 %[output:1828cff7]
axis(200 * [-1 1 -1 1]); % x축 -200~200 y축 -200~200 %[output:1828cff7]
%%
%[text] 
%[text] - $y \> x + 100$의 영역은 밝기 200으로 설정 \
clear;
h = 400; % 높이
w = 400; % 폭
[X, Y] = meshgrid(-w/2:(w/2-1), h/2-1: -1: -h/2);
% X축 범위: -200:199 Y축 범위: 199:-200
% Y축이 양수 -> 음수인 이유: 인덱스는 위에서 아래로
%[X, Y] 좌표
G = zeros(h, w, 'uint8');
%400x400 사이즈 검은색
Z = Y - X -100;
% Y = X + 100
M = Z > 0;
%Logical: Z>0 이면 1, <0 이면 0
G(M) = 200;
% y > x + 100인 영역 밝기 200
imshow(G) %[output:9ecd92ef]
%%
%[text] 
%[text] ### 두 영역의 부등식 적용하기
%[text] - 영역 1: y \> x +100
%[text] - 영역 2: y \> -x -100 \
clear;
h = 400;
w = 400;

[X, Y] = meshgrid(-w/2:w/2-1, h/2-1:-1:-h/2);
G = zeros(h, w, 'uint8');

Z = Y -X -100;
M = Z > 0;
G(M) = 150;

Z = Y +X +100;
M = Z > 0;
G(M) = G(M) + 100;
imshow(G) %[output:7e374105]
%%
%[text] ## 연습 문제 4: 두 부등식 영역으로 이미지 만들기
%[text] - 이전과 동일한 크기의 흑백 이미지에서 다음 두 직선에 의해 만들어지는 영역들을 각각 서로 다른 밝기로 나타내시오
%[text] - $y = x + 100$
%[text] - $y = x -100$ \
clear;
h = 400; % 높이
w = 400; % 폭

[X, Y] = meshgrid(-w/2:w/2-1, h/2-1:-1:-h/2);

G = zeros(h, w, 'uint8');

Z = Y -X -100;
M = Z > 0;
G(M) = 50;

Z = Y -X +100;
M = Z > 0;
G(M) = G(M) + 50;

Result = padarray(G, [10 10], 0, 'both');

imshow(Result); %[output:1f2776a8]
%%
%[text] ## 곡선 영역 적용하기
%[text] - 원 영역: $(x-150)^2 +y^2 \< 150^2$
%[text] - 포물선 영역: $y \< -0.01 .\\times x^2 + 200$ \
clear;
h = 400; % 높이
w = 400; % 폭

[X, Y] = meshgrid(-w/2:w/2-1, h/2-1:-1:-h/2);
% X축 범위: -200 ~ 199 Y축 범위: 199 ~ -200

G = zeros(h, w, 'uint8');
% 검은 사각형 400x400

Z1 = (X -150).^2 + Y.^2; % 원 영역
M1 = Z1 < 150^2;
G(M1) = 170; %픽셀 밝기 170

Z2 = Y + 0.01*X.^2 -200; % 포물선 영역
M2 = Z2 < 0;
G(M2) = G(M2) + 80; % 포물선 영역 아래 픽셀 밝기 80에 겹치기

imshow(G) %[output:52aa7df4]
%%
%[text] ## 연습 문제 5: 곡선 이미지 만들기
%[text] - 크기는 이전과 동일. 밝기는 각각 0과 200
%[text] - $(x-200)^2 + (y-200)^2 = 400^2$
%[text] - $(x+200)^2 + (y-200)^2 = 400^2$
%[text] - $(x-200)^2 + (y+200)^2 = 400^2$
%[text] - $(x+200)^2 + (y+200)^2 = 400^2$ \
clear;

h = 400; % 높이
w = 400; % 폭

[X, Y] = meshgrid(-w/2:w/2-1, h/2-1:-1:-h/2);
% X의 범위: -200 ~ 199 Y의 범위: 199 ~ -200 
G = ones(h, w, 'uint8');
% 400x400 사이즈의 1로된 uint8 행렬

Z1 = (X-200).^2 + (Y-200).^2;
M1 = Z1 > 400^2; %logical: True = 1 False = 0
G(M1) = G(M1) + 199; % 400x400 사이즈의 1로된 uint8 행렬이기에 +199 하면 200

Z2 = (X+200).^2 + (Y-200).^2;
M2 = Z2 > 400^2;
G(M2) = G(M2) + 199;

Z3 = (X-200).^2 + (Y+200).^2;
M3 = Z3 > 400^2;
G(M3) = G(M3) + 199;

Z4 = (X+200).^2 + (Y+200).^2;
M4 = Z4 > 400^2;
G(M4) = G(M4) + 199;
imshow(G) %[output:8198434a]
C = M1 + M2 + M3 + M4; % logical 행렬들 더하기
G(C >= 2) = 0; % 행렬들 더했을 때 2 이상이면 0으로 처리 == 2개 이상 겹칠 때 검정으로 처리

imshow(G) %[output:0ba43d42]
Frame = padarray(G, [10 10], 255, 'both');
Result = padarray(Frame, [10, 10], 0, 'both');

imshow(Result) %[output:67fb741b]
